-- Create the new table AÇOES DE COBRANÇA
CREATE TABLE "AÇOES DE COBRANÇA" (
    "ID AÇÃO" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CLIENTE" TEXT,
    "COD. CLIENTE" INTEGER,
    "CÓDIGO FUNCIONÁRIO" INTEGER,
    "NOME FUNCIONÁRIO" TEXT,
    "DATA AÇÃO COBRANÇA" DATE,
    "AÇÃO DE COBRANÇA" TEXT,
    "NOVA DATA COMBINADA PAGAMENTO" DATE,
    "NÚMERO DO PEDIDO" INTEGER
);

-- Drop the old table COBRANÇA
DROP TABLE IF EXISTS "COBRANÇA";
